import{_ as a,c as e,o as s,a2 as t}from"./chunks/framework.CbocFKz0.js";const m=JSON.parse('{"title":"BootWay03 (半自动) 教程","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/boot/shell/BootWay03-Linux-SemiAuto.md","filePath":"zh-CN/guide/boot/shell/BootWay03-Linux-SemiAuto.md","lastUpdated":1723730291000}'),n={name:"zh-CN/guide/boot/shell/BootWay03-Linux-SemiAuto.md"},o=t(`<h1 id="bootway03-半自动-教程" tabindex="-1">BootWay03 (半自动) 教程 <a class="header-anchor" href="#bootway03-半自动-教程" aria-label="Permalink to &quot;BootWay03 (半自动) 教程&quot;">​</a></h1><p>手动安装 Linux QQ，并用你的包管理器安装以下包：<code>zip unzip jq curl xvfb screen</code>。</p><p>下载<a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">最新 NapCat Release</a> 中的 <code>NapCat.Shell.zip</code> 到用户目录某处（建议先切换到 <code>bash</code> 或者 <code>zsh</code>，不知道这是什么的就不用管了），然后复制以下内容，粘贴到终端里，然后按下 Enter 执行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir ./NapCat/</span></span>
<span class="line"><span>mkdir ./tmp/</span></span>
<span class="line"><span>unzip -q -o -d ./tmp NapCat.Shell.zip</span></span>
<span class="line"><span>target_folder=&quot;/opt/QQ/resources/app/app_launcher&quot;</span></span>
<span class="line"><span>default_file=&quot;NapCat.shell.zip&quot;</span></span>
<span class="line"><span>sudo cp -r -f ./tmp/*  &quot;$target_folder/napcat/&quot;</span></span>
<span class="line"><span>sudo chmod -R 777 &quot;$target_folder/napcat/&quot;</span></span>
<span class="line"><span>sudo mv -f &quot;$target_folder/index.js&quot; &quot;$target_folder/index.js.bak&quot;</span></span>
<span class="line"><span>output_index_js=$(echo -e &quot;const path = require(&#39;path&#39;);\\nconst CurrentPath = path.dirname(__filename)\\nconst hasNapcatParam = process.argv.includes(&#39;--no-sandbox&#39;);\\nif (hasNapcatParam) {\\n    (async () =&gt; {\\n        await import(\\\\\\&quot;file://\\\\\\&quot; + path.join(CurrentPath, &#39;./napcat/napcat.mjs&#39;));\\n    })();\\n} else {\\n    require(&#39;./launcher.node&#39;).load(&#39;external_index&#39;, module);\\n}&quot;)</span></span>
<span class="line"><span>sudo bash -c &quot;echo \\&quot;$output_index_js\\&quot; &gt; \\&quot;$target_folder/index.js\\&quot;&quot;</span></span></code></pre></div><p>然后使用</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xvfb-run -a qq --no-sandbox -q</span></span></code></pre></div><p>或者</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xvfb-run -a linuxqq --no-sandbox -q</span></span></code></pre></div><p>来启动 NapCat。</p>`,9),p=[o];function i(l,c,d,u,r,h){return s(),e("div",null,p)}const q=a(n,[["render",i]]);export{m as __pageData,q as default};
